spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 11000;
    var progressMs = t % duration;
    var seconds = progressMs / 1000;

    var fenceMaxW = 110;
    var fenceStartX = W / 2 - 20;

    // Lanes Y-centers
    var y1 = H / 2 - 42;
    var y2 = H / 2 - 12;
    var y3 = H / 2 + 18;
    var laneH = 16;

    // Paint completion times (sec):
    // Lane 1: 8 sec (speed = fenceMaxW / 8)
    // Lane 2: 4 sec (speed = fenceMaxW / 4)
    // Lane 3: 2 sec (speed = fenceMaxW / 2)

    var t1 = Math.min(seconds, 8);
    var t2 = Math.min(seconds, 4);
    var t3 = Math.min(seconds, 2);

    var fillW1 = (t1 / 8) * fenceMaxW;
    var fillW2 = (t2 / 4) * fenceMaxW;
    var fillW3 = (t3 / 2) * fenceMaxW;

    // Helper to draw a lane
    function drawLane(ly, fillW, workersCount, labelText, color) {
      // Fence background
      ctx.fillStyle = '#1F2937';
      ctx.fillRect(fenceStartX, ly - laneH/2, fenceMaxW, laneH);
      ctx.strokeStyle = '#4B5563';
      ctx.lineWidth = 1;
      ctx.strokeRect(fenceStartX, ly - laneH/2, fenceMaxW, laneH);

      // Painted section
      ctx.fillStyle = color;
      ctx.fillRect(fenceStartX, ly - laneH/2, fillW, laneH);

      // Draw worker circles on the left
      for (var i = 0; i < workersCount; i++) {
        var wx = fenceStartX - 15 - i * 11;
        ctx.fillStyle = '#E5E7EB';
        ctx.beginPath();
        ctx.arc(wx, ly, 4, 0, Math.PI * 2);
        ctx.fill();
      }

      // Label
      ctx.font = '9px monospace';
      ctx.fillStyle = '#9CA3AF';
      ctx.textAlign = 'left';
      ctx.textBaseline = 'middle';
      ctx.fillText(labelText, fenceStartX + fenceMaxW + 8, ly);
    }

    // Draw Lanes
    drawLane(y1, fillW1, 1, '1 Crew: 8s', '#3B82F6');
    drawLane(y2, fillW2, 2, '2 Crew: 4s', '#10B981');
    drawLane(y3, fillW3, 4, '4 Crew: 2s', '#F59E0B');

    // Top Stats Title
    ctx.fillStyle = '#E5E7EB';
    ctx.font = 'bold 11px monospace';
    ctx.textAlign = 'center';
    ctx.fillText('Job: Paint a 110m Fence Panel', W / 2, 20);

    // Product details
    ctx.fillStyle = '#F59E0B';
    ctx.fillText('Workers × Time = 8 Worker-Seconds (Constant Product)', W / 2, 36);

    // Explanations
    ctx.font = 'bold 15px -apple-system, sans-serif';
    ctx.fillStyle = '#F3F4F6';
    ctx.fillText('w × t = 8', W / 2, H - 42);
    ctx.font = '11px -apple-system, sans-serif';
    ctx.fillStyle = '#9CA3AF';
    ctx.fillText('Double the crew, half the time. The work size remains constant.', W / 2, H - 22);
  }
};
